import React, { useState, useEffect, useRef } from 'react';
import './Community.css';

// Sample data
const initialMoodWall = [
  {
    id: 1, 
    userName: "MindfulExplorer", 
    text: "Just completed my first mindfulness meditation. Feeling incredible peace and clarity! 🌿", 
    likes: 284,
    comments: 42,
    shares: 18,
    mood: "peaceful",
    timestamp: "2 minutes ago",
    userLevel: 27,
    userBadges: ["Meditation Expert", "Wellness Champion"],
    verified: true,
    liked: false
  },
  {
    id: 2, 
    userName: "CalmGuide", 
    text: "Our mindfulness group just had an amazing session. The positive energy was palpable! ✨", 
    likes: 567,
    comments: 89,
    shares: 34,
    mood: "calm",
    timestamp: "15 minutes ago",
    userLevel: 42,
    userBadges: ["Mindfulness Teacher", "Group Leader"],
    verified: true,
    liked: false
  }
];

const initialGroups = [
  {
    id: 1, 
    name: "📚 Study Stress & Exams", 
    description: "Share strategies for managing academic pressure and exam anxiety.", 
    members: 2456, 
    isMember: false,
    engagementLevel: 82,
    activity: "high",
    tags: ["academic", "exams", "stress"],
    lastMessage: "Remember to take regular breaks while studying. Pomodoro technique works wonders!",
    lastMessageTime: "9:30 AM",
    unreadCount: 0,
    messages: [
      { 
        id: 1, 
        user: "StudyGuide", 
        text: "Remember to take regular breaks while studying. Pomodoro technique works wonders!", 
        time: "9:30 AM",
        reactions: { like: 5, heart: 2, support: 3 },
        replies: [
          { id: 1, user: "Student123", text: "Thanks for the tip! I'll try this today.", time: "9:45 AM" },
          { id: 2, user: "FocusedMind", text: "Pomodoro changed my study habits completely!", time: "10:15 AM" }
        ]
      },
      { 
        id: 2, 
        user: "ExamSurvivor", 
        text: "Anyone have tips for dealing with test anxiety?", 
        time: "10:45 AM",
        reactions: { like: 8, support: 5 },
        replies: []
      }
    ]
  },
  {
    id: 2, 
    name: "💬 Friends & Social Life", 
    description: "Navigate social challenges and build healthier relationships.", 
    members: 1873, 
    isMember: false,
    engagementLevel: 78,
    activity: "medium",
    tags: ["friendship", "social", "relationships"],
    lastMessage: "How do you maintain friendships when you're feeling down?",
    lastMessageTime: "10:15 AM",
    unreadCount: 0,
    messages: [
      { 
        id: 1, 
        user: "SocialButterfly", 
        text: "How do you maintain friendships when you're feeling down?", 
        time: "10:15 AM",
        reactions: { like: 4, heart: 7 },
        replies: []
      }
    ]
  },
  {
    id: 3, 
    name: "🏠 Family & Home Issues", 
    description: "Find support for family dynamics and home-related challenges.", 
    members: 1562, 
    isMember: false,
    engagementLevel: 75,
    activity: "medium",
    tags: ["family", "home", "support"],
    lastMessage: "Dealing with family expectations can be overwhelming sometimes.",
    lastMessageTime: "8:30 AM",
    unreadCount: 0,
    messages: [
      { 
        id: 1, 
        user: "FamilyFirst", 
        text: "Dealing with family expectations can be overwhelming sometimes.", 
        time: "8:30 AM",
        reactions: { like: 6, support: 3 },
        replies: []
      }
    ]
  },
  {
    id: 4, 
    name: "💼 Work & Career Pressure", 
    description: "Manage workplace stress and career-related anxieties.", 
    members: 2894, 
    isMember: false,
    engagementLevel: 85,
    activity: "high",
    tags: ["work", "career", "pressure"],
    lastMessage: "Work-life balance is essential for mental health.",
    lastMessageTime: "9:15 AM",
    unreadCount: 0,
    messages: [
      { 
        id: 1, 
        user: "CareerCoach", 
        text: "Work-life balance is essential for mental health.", 
        time: "9:15 AM",
        reactions: { like: 9, support: 4 },
        replies: []
      }
    ]
  },
  {
    id: 5, 
    name: "💔 Breakups & Relationships", 
    description: "Heal from heartbreak and navigate relationship challenges.", 
    members: 3217, 
    isMember: false,
    engagementLevel: 88,
    activity: "very high",
    tags: ["breakups", "relationships", "healing"],
    lastMessage: "Breakups are tough but remember you're not alone in this.",
    lastMessageTime: "10:30 AM",
    unreadCount: 0,
    messages: [
      { 
        id: 1, 
        user: "HealingHeart", 
        text: "Breakups are tough but remember you're not alone in this.", 
        time: "10:30 AM",
        reactions: { like: 12, heart: 8, support: 5 },
        replies: []
      }
    ]
  }
];

const initialLiveEvents = [
  {
    id: 1,
    title: "Guided Meditation Session",
    host: "Mindfulness Coach Sarah",
    participants: 1247,
    startTime: "30 minutes",
    duration: "45 min",
    energyLevel: "calm",
    description: "Join us for a peaceful guided meditation session to reduce stress and improve focus."
  },
  {
    id: 2,
    title: "Anxiety Management Workshop",
    host: "Dr. James Peterson",
    participants: 874,
    startTime: "2 hours",
    duration: "1 hour",
    energyLevel: "informative",
    description: "Learn practical techniques to manage anxiety in daily life from a licensed therapist."
  }
];

function Community({ user }) {
  const [moodWall, setMoodWall] = useState(initialMoodWall);
  const [groups, setGroups] = useState(initialGroups);
  const [activeTab, setActiveTab] = useState('groups');
  const [selectedGroup, setSelectedGroup] = useState(null);
  const [newPostText, setNewPostText] = useState('');
  const [isCreatingPost, setIsCreatingPost] = useState(false);
  const [newMessage, setNewMessage] = useState('');
  const [replyingTo, setReplyingTo] = useState(null);
  const [editingMessage, setEditingMessage] = useState(null);
  const [replyText, setReplyText] = useState('');
  const [eventReminders, setEventReminders] = useState({});
  const messagesEndRef = useRef(null);

  // Scroll to bottom of chat
  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [selectedGroup?.messages, replyingTo]);

  const handleAddPost = () => {
    if (newPostText.trim() !== "") {
      const newPost = {
        id: Date.now(),
        userName: user?.username || "Anonymous",
        text: newPostText,
        likes: 0,
        comments: 0,
        shares: 0,
        mood: "neutral",
        timestamp: "Just now",
        userLevel: user?.level || 1,
        userBadges: user?.badges || ["New Member"],
        verified: user?.verified || false,
        liked: false
      };
      setMoodWall(prev => [newPost, ...prev]);
      setNewPostText('');
      setIsCreatingPost(false);
    }
  };

  const handleJoinGroup = (groupId) => {
    setGroups(prevGroups => 
      prevGroups.map(group => 
        group.id === groupId ? { 
          ...group, 
          isMember: !group.isMember, 
          members: group.isMember ? group.members - 1 : group.members + 1 
        } : group
      )
    );
  };

  const handleLikePost = (postId) => {
    setMoodWall(prev => 
      prev.map(post => 
        post.id === postId ? { 
          ...post, 
          likes: post.liked ? post.likes - 1 : post.likes + 1,
          liked: !post.liked
        } : post
      )
    );
  };

  const handleSendMessage = () => {
    if (newMessage.trim() !== "" && selectedGroup) {
      const updatedGroups = groups.map(group => {
        if (group.id === selectedGroup.id) {
          const newMessageObj = {
            id: group.messages.length + 1,
            user: user?.username || "You",
            text: newMessage,
            time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
            reactions: {},
            replies: []
          };
          
          return {
            ...group,
            messages: [...group.messages, newMessageObj],
            lastMessage: newMessage,
            lastMessageTime: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
          };
        }
        return group;
      });
      
      setGroups(updatedGroups);
      setSelectedGroup(updatedGroups.find(g => g.id === selectedGroup.id));
      setNewMessage('');
    }
  };

  const handleReactToMessage = (groupId, messageId, reaction) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.map(message => {
          if (message.id === messageId) {
            const currentReactions = { ...message.reactions };
            currentReactions[reaction] = (currentReactions[reaction] || 0) + 1;
            return {
              ...message,
              reactions: currentReactions
            };
          }
          return message;
        });
        
        return {
          ...group,
          messages: updatedMessages
        };
      }
      return group;
    });
    
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
  };

  const handleReplyToMessage = (groupId, messageId) => {
    if (replyText.trim() !== "") {
      const updatedGroups = groups.map(group => {
        if (group.id === groupId) {
          const updatedMessages = group.messages.map(message => {
            if (message.id === messageId) {
              const newReply = {
                id: message.replies.length + 1,
                user: user?.username || "You",
                text: replyText,
                time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
              };
              
              return {
                ...message,
                replies: [...message.replies, newReply]
              };
            }
            return message;
          });
          
          return {
            ...group,
            messages: updatedMessages
          };
        }
        return group;
      });
      
      setGroups(updatedGroups);
      if (selectedGroup && selectedGroup.id === groupId) {
        setSelectedGroup(updatedGroups.find(g => g.id === groupId));
      }
      setReplyText('');
      setReplyingTo(null);
    }
  };

  const handleEditMessage = (groupId, messageId, newText) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.map(message => {
          if (message.id === messageId && message.user === (user?.username || "You")) {
            return {
              ...message,
              text: newText,
              edited: true
            };
          }
          return message;
        });
        
        return {
          ...group,
          messages: updatedMessages
        };
      }
      return group;
    });
    
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
    setEditingMessage(null);
  };

  const handleDeleteMessage = (groupId, messageId) => {
    const updatedGroups = groups.map(group => {
      if (group.id === groupId) {
        const updatedMessages = group.messages.filter(message => 
          !(message.id === messageId && message.user === (user?.username || "You"))
        );
        
        return {
          ...group,
          messages: updatedMessages
        };
      }
      return group;
    });
    
    setGroups(updatedGroups);
    if (selectedGroup && selectedGroup.id === groupId) {
      setSelectedGroup(updatedGroups.find(g => g.id === groupId));
    }
  };

  const handleJoinEvent = (eventId) => {
    alert(`You've joined the event! We'll send you a reminder before it starts.`);
  };

  const handleSetReminder = (eventId) => {
    setEventReminders(prev => ({
      ...prev,
      [eventId]: true
    }));
    alert(`Reminder set for this event!`);
  };

  const renderActivityLevel = (level) => {
    const levels = {
      "very high": { color: "#00b894", label: "Very Active" },
      "high": { color: "#00b894", label: "Active" },
      "medium": { color: "#fdcb6e", label: "Moderate" },
      "low": { color: "#e17055", label: "Low" }
    };
    
    return (
      <span className="activity-level" style={{ color: levels[level]?.color }}>
        ● {levels[level]?.label}
      </span>
    );
  };

  return (
    <div className="community-hub">
      {/* Compact Header */}
      <div className="community-header">
        <div className="header-content">
          <h1>Community</h1>
          <div className="header-controls">
            <button className={`header-tab ${activeTab === 'feed' ? 'active' : ''}`} 
                    onClick={() => setActiveTab('feed')}>
              Feed
            </button>
            <button className={`header-tab ${activeTab === 'groups' ? 'active' : ''}`} 
                    onClick={() => setActiveTab('groups')}>
              Groups
            </button>
            <button className={`header-tab ${activeTab === 'events' ? 'active' : ''}`} 
                    onClick={() => setActiveTab('events')}>
              Events
            </button>
          </div>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="community-main">
        {activeTab === 'feed' && (
          <div className="feed-view">
            <div className="create-post">
              <div className="post-input-container">
                <div className="user-avatar small">
                  {user?.username?.charAt(0) || "A"}
                </div>
                <input 
                  type="text"
                  placeholder="Share your thoughts with the community..."
                  onClick={() => setIsCreatingPost(true)}
                  className="post-input-trigger"
                />
              </div>
              
              {isCreatingPost && (
                <div className="post-modal">
                  <div className="modal-header">
                    <h3>Create Post</h3>
                    <button className="close-modal" onClick={() => {
                      setIsCreatingPost(false);
                      setNewPostText('');
                    }}>×</button>
                  </div>
                  <div className="modal-content">
                    <textarea 
                      placeholder="What's on your mind?"
                      value={newPostText}
                      onChange={(e) => setNewPostText(e.target.value)}
                      autoFocus
                    ></textarea>
                    <div className="post-actions-modal">
                      <button className="cancel-post" onClick={() => {
                        setIsCreatingPost(false);
                        setNewPostText('');
                      }}>Cancel</button>
                      <button className="share-post" onClick={handleAddPost} disabled={!newPostText.trim()}>
                        Post
                      </button>
                    </div>
                  </div>
                </div>
              )}
            </div>

            <div className="posts-list">
              {moodWall.map(post => (
                <div key={post.id} className="post-card">
                  <div className="post-header">
                    <div className="post-user">
                      <div className="user-avatar">{post.userName.charAt(0)}</div>
                      <div className="user-info">
                        <div className="user-name">
                          {post.userName}
                          {post.verified && <span className="verified">✓</span>}
                        </div>
                        <div className="post-meta">
                          <span className="timestamp">{post.timestamp}</span>
                          <span className="user-level">Level {post.userLevel}</span>
                        </div>
                      </div>
                    </div>
                  </div>
                  <div className="post-content">
                    <p>{post.text}</p>
                  </div>
                  <div className="post-actions">
                    <button 
                      className={`action-btn like ${post.liked ? 'active' : ''}`}
                      onClick={() => handleLikePost(post.id)}
                    >
                      👍 {post.likes}
                    </button>
                    <button className="action-btn comment">
                      💬 {post.comments}
                    </button>
                    <button className="action-btn share">
                      ↗️ {post.shares}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'groups' && (
          <div className="groups-view">
            {!selectedGroup ? (
              <div className="groups-list">
                <div className="groups-header">
                  <h2>Support Groups</h2>
                  <div className="search-box">
                    <input type="text" placeholder="Search groups..." />
                  </div>
                </div>
                
                <div className="groups-container">
                  {groups.map(group => (
                    <div 
                      key={group.id} 
                      className="group-item"
                      onClick={() => setSelectedGroup(group)}
                    >
                      <div className="group-avatar">
                        {group.name.charAt(0)}
                      </div>
                      <div className="group-info">
                        <div className="group-header">
                          <h3>{group.name}</h3>
                          <span className="last-message-time">{group.lastMessageTime}</span>
                        </div>
                        <div className="group-preview">
                          <p className="last-message">{group.lastMessage}</p>
                          {group.unreadCount > 0 && (
                            <span className="unread-badge">{group.unreadCount}</span>
                          )}
                        </div>
                        <div className="group-meta">
                          <span className="members">👥 {group.members} members</span>
                          {renderActivityLevel(group.activity)}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ) : (
              <div className="chat-interface">
                <div className="chat-header">
                  <div className="chat-header-left">
                    <button className="back-btn" onClick={() => setSelectedGroup(null)}>
                      ←
                    </button>
                    <div className="chat-group-info">
                      <h3>{selectedGroup.name}</h3>
                      <span className="online-status">
                        {selectedGroup.members} members • {renderActivityLevel(selectedGroup.activity)}
                      </span>
                    </div>
                  </div>
                  <div className="chat-header-right">
                    {!selectedGroup.isMember && (
                      <button 
                        className="join-chat-btn"
                        onClick={() => handleJoinGroup(selectedGroup.id)}
                      >
                        Join Group
                      </button>
                    )}
                  </div>
                </div>

                <div className="chat-messages">
                  {selectedGroup.messages.map(message => (
                    <div key={message.id} className="message-wrapper">
                      <div className={`message ${message.user === (user?.username || "You") ? 'sent' : 'received'}`}>
                        <div className="message-content">
                          {message.user !== (user?.username || "You") && (
                            <div className="sender-name">{message.user}</div>
                          )}
                          <div className="message-bubble">
                            {editingMessage && editingMessage.id === message.id ? (
                              <div className="edit-message">
                                <input
                                  type="text"
                                  value={editingMessage.text}
                                  onChange={(e) => setEditingMessage({...editingMessage, text: e.target.value})}
                                  className="edit-input"
                                />
                                <div className="edit-actions">
                                  <button onClick={() => handleEditMessage(selectedGroup.id, message.id, editingMessage.text)}>
                                    Save
                                  </button>
                                  <button onClick={() => setEditingMessage(null)}>
                                    Cancel
                                  </button>
                                </div>
                              </div>
                            ) : (
                              <p>{message.text}</p>
                            )}
                            <span className="message-time">{message.time}</span>
                          </div>
                          
                          {message.user === (user?.username || "You") && (
                            <div className="message-actions">
                              <button onClick={() => setEditingMessage({id: message.id, text: message.text})}>
                                Edit
                              </button>
                              <button onClick={() => handleDeleteMessage(selectedGroup.id, message.id)}>
                                Delete
                              </button>
                            </div>
                          )}
                        </div>
                      </div>

                      {replyingTo === message.id && (
                        <div className="reply-input">
                          <input
                            type="text"
                            placeholder="Type your reply..."
                            value={replyText}
                            onChange={(e) => setReplyText(e.target.value)}
                          />
                          <button onClick={() => handleReplyToMessage(selectedGroup.id, message.id)}>
                            Send
                          </button>
                          <button onClick={() => setReplyingTo(null)}>Cancel</button>
                        </div>
                      )}
                    </div>
                  ))}
                  <div ref={messagesEndRef} />
                </div>

                <div className="chat-input-wrapper">
                  <div className="chat-input-container">
                    <input
                      type="text"
                      placeholder="Type a message..."
                      value={newMessage}
                      onChange={(e) => setNewMessage(e.target.value)}
                      onKeyPress={(e) => e.key === 'Enter' && handleSendMessage()}
                    />
                    <button 
                      onClick={handleSendMessage}
                      disabled={!newMessage.trim()}
                      className="send-btn"
                    >
                      Send
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {activeTab === 'events' && (
          <div className="events-view">
            <h2>Live Events & Workshops</h2>
            <div className="events-list">
              {initialLiveEvents.map(event => (
                <div key={event.id} className="event-card">
                  <div className="event-header">
                    <h3>{event.title}</h3>
                    <span className="event-status live">LIVE</span>
                  </div>
                  <div className="event-details">
                    <p className="event-description">{event.description}</p>
                    <div className="event-meta">
                      <span>👤 {event.host}</span>
                      <span>👥 {event.participants} participants</span>
                      <span>⏰ Starts in {event.startTime}</span>
                    </div>
                  </div>
                  <div className="event-actions">
                    <button 
                      className="join-event"
                      onClick={() => handleJoinEvent(event.id)}
                    >
                      Join Event
                    </button>
                    <button 
                      className={`reminder ${eventReminders[event.id] ? 'set' : ''}`}
                      onClick={() => handleSetReminder(event.id)}
                    >
                      {eventReminders[event.id] ? 'Reminder Set' : 'Set Reminder'}
                    </button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Community;
